channels = get_channels()

# Collect all users from all channels
all_users = set()
all_users = {u for ch in channels for u in get_users_in_channel(ch)}

# Count messages per user across all channels
message_counts = {u: 0 for u in all_users}
for ch in channels:
    msgs = read_channel_messages(ch)
    for m in msgs:
        if m.sender in message_counts:
            message_counts[m.sender] = message_counts[m.sender] + 1

# Sort by count descending, then alphabetically ascending
sorted_users = sorted(message_counts.items(), key=lambda x: (-x[1], x[0]))

for rank, (user, count) in enumerate(sorted_users, start=1):
    send_direct_message(user, f"Congrats on being the {rank}-th most active user!")
